		Name:        p.Name,
		Roles:       p.Roles,
		Description: p.Description,
		Tags:        p.Tags,
		Content:     p.Content,
		Body:        p.Content,
		Source:      source,
		Bindings:    []*PersonaBinding{},
		FilePath:    filePath,
	}
